import { WorkHistoryModel } from '../../apis/models/work-history';
import styles from './style.module.css';

export function WorkHistory({ list }: { list: WorkHistoryModel[] }) {

    return (
        <div className={`${styles.work_history} ${styles.parts} ${styles.bottom_part}`}>

            <div className={styles.part_title_container}>
                <span className={styles.part_title}>Work History</span>
            </div>

            <div className={styles.part_context}>

                {list.map(model => {
                    return (
                        <div className={styles.work_container}>
                            <div className={styles.line}><i className="material-icons">code</i></div>
                            <div className={styles.job_title}><span>{model.title}</span></div>
                            <div className={styles.company_name}>{model.company}</div>
                            <div className={styles.time_range}><span className={styles.time}>{model.startTime}</span> to <span className={styles.time}>{model.endTime}</span></div>
                            <div className={styles.job_description}>
                                {model.description?.split("\n").map(x => {
                                    return (<span>{x}<br/></span>)
                                })}
                            </div>
                        </div>
                    )
                })}

            </div>
        </div>
    )

}